'use strict';

/**
 * GSD-T CLI Preflight (M55 D1)
 *
 * Pluggable, deterministic, zero-dep state-precondition library + thin CLI.
 *
 * Pure inspector — no LLM spawn, no token spend, no side effects beyond reading
 * the filesystem and running a small fixed list of read-only `git` / `lsof`
 * commands inside individual checks.
 *
 * Contract: .gsd-t/contracts/cli-preflight-contract.md v1.0.0 STABLE.
 *
 * Hard rules (mirroring bin/parallelism-report.cjs):
 *   1. Zero external runtime deps. Only Node built-ins.
 *   2. Synchronous public API; never throws to the caller.
 *   3. Per-check throws are caught, recorded, do not abort the run.
 *   4. Deterministic output — sort `checks[]` by id, sort `notes[]`.
 *   5. captureSpawn-exempt — see contract § captureSpawn Exemption.
 */

const fs = require('fs');
const path = require('path');

const SCHEMA_VERSION = '1.0.0';
const CHECKS_DIR_NAME = 'cli-preflight-checks';
const VALID_SEVERITIES = new Set(['error', 'warn', 'info']);

// ── Public API ──────────────────────────────────────────────────────────────

/**
 * @param {object} [opts]
 * @param {string} [opts.projectDir='.']
 * @param {string[]} [opts.checks]   restrict to these check ids (default = all built-ins)
 * @param {string} [opts.mode='json'] informational; envelope is identical
 * @returns {{ ok: boolean, schemaVersion: string, checks: object[], notes: string[] }}
 */
function runPreflight(opts) {
  opts = opts || {};
  const projectDir = opts.projectDir || '.';
  const restrict = Array.isArray(opts.checks) ? new Set(opts.checks) : null;
  const notes = [];

  const registry = _loadRegistry(notes);

  const selected = restrict
    ? registry.filter((c) => restrict.has(c.id))
    : registry;

  const checkResults = [];
  for (const check of selected) {
    const result = _runOneCheck(check, { projectDir }, notes);
    checkResults.push(result);
  }

  // Sort checks by id, ascending. Sort notes ascending.
  checkResults.sort((a, b) => (a.id < b.id ? -1 : a.id > b.id ? 1 : 0));
  notes.sort();

  const ok = !checkResults.some((c) => c.ok === false && c.severity === 'error');

  return {
    schemaVersion: SCHEMA_VERSION,
    ok,
    checks: checkResults,
    notes,
  };
}

/**
 * Render an envelope as a human-readable text summary.
 * @param {object} envelope
 * @returns {string}
 */
function renderText(envelope) {
  const lines = [];
  const status = envelope.ok ? 'OK' : 'FAIL';
  lines.push('cli-preflight: ' + status + ' (schema v' + envelope.schemaVersion + ')');
  lines.push('');
  for (const c of envelope.checks) {
    const icon = c.ok ? '✓' : (c.severity === 'error' ? '✗' : '!');
    lines.push('  ' + icon + ' [' + c.severity.padEnd(5) + '] ' + c.id + ' — ' + c.msg);
  }
  if (envelope.notes && envelope.notes.length) {
    lines.push('');
    lines.push('Notes:');
    for (const n of envelope.notes) lines.push('  - ' + n);
  }
  return lines.join('\n');
}

// ── Internal helpers ────────────────────────────────────────────────────────

function _loadRegistry(notes) {
  const dir = path.join(__dirname, CHECKS_DIR_NAME);
  let entries;
  try {
    entries = fs.readdirSync(dir);
  } catch (err) {
    notes.push('registry: checks dir unreadable (' + (err && err.message || err) + ')');
    return [];
  }

  const checks = [];
  for (const filename of entries) {
    if (!filename.endsWith('.cjs')) continue;
    const full = path.join(dir, filename);
    let mod;
    try {
      mod = require(full);
    } catch (err) {
      notes.push('registry: ' + filename + ' load failed (' + (err && err.message || err) + ')');
      continue;
    }
    if (!_isValidCheckModule(mod, filename)) {
      notes.push('registry: ' + filename + ' malformed');
      continue;
    }
    checks.push(mod);
  }
  // Sort registry deterministically too — order of execution doesn't affect
  // output (results are sorted again before return) but stable order makes
  // notes ordering predictable.
  checks.sort((a, b) => (a.id < b.id ? -1 : a.id > b.id ? 1 : 0));
  return checks;
}

function _isValidCheckModule(mod, filename) {
  if (!mod || typeof mod !== 'object') return false;
  if (typeof mod.id !== 'string' || !mod.id.length) return false;
  if (!VALID_SEVERITIES.has(mod.severity)) return false;
  if (typeof mod.run !== 'function') return false;
  // Filename stem must match id, so a directory scan = a stable id namespace.
  const stem = filename.replace(/\.cjs$/, '');
  if (stem !== mod.id) return false;
  return true;
}

function _runOneCheck(check, ctx, notes) {
  let raw;
  try {
    raw = check.run(ctx);
  } catch (err) {
    const msg = 'check threw: ' + (err && err.message || String(err));
    notes.push(check.id + ': ' + msg);
    return {
      id: check.id,
      ok: false,
      severity: check.severity,
      msg,
    };
  }

  if (!raw || typeof raw !== 'object' || typeof raw.ok !== 'boolean') {
    const msg = 'check returned invalid shape';
    notes.push(check.id + ': ' + msg);
    return {
      id: check.id,
      ok: false,
      severity: check.severity,
      msg,
    };
  }

  const out = {
    id: check.id,
    ok: raw.ok,
    severity: check.severity,
    msg: typeof raw.msg === 'string' ? raw.msg : '',
  };
  if (raw.details && typeof raw.details === 'object' && Object.keys(raw.details).length > 0) {
    out.details = raw.details;
  }
  return out;
}

// ── CLI ─────────────────────────────────────────────────────────────────────

function _parseArgv(argv) {
  const out = { projectDir: '.', mode: 'json', skip: [] };
  for (let i = 0; i < argv.length; i++) {
    const a = argv[i];
    if (a === '--project') {
      out.projectDir = argv[++i] || '.';
    } else if (a === '--json') {
      out.mode = 'json';
    } else if (a === '--text') {
      out.mode = 'text';
    } else if (a === '--skip') {
      const list = argv[++i] || '';
      out.skip = list.split(',').map((s) => s.trim()).filter(Boolean);
    } else if (a === '--help' || a === '-h') {
      out.help = true;
    }
  }
  return out;
}

function _printHelp() {
  const lines = [
    'Usage: node bin/cli-preflight.cjs [options]',
    '',
    'Options:',
    '  --project DIR     Project root (default: .)',
    '  --json            Print JSON envelope (default)',
    '  --text            Print human-readable summary',
    '  --skip id1,id2    Skip listed checks (each appends a note)',
    '  --help            Show this help',
    '',
    'Exit codes:',
    '  0  preflight ok',
    '  4  preflight failed (>=1 error-severity check failed)',
  ];
  process.stdout.write(lines.join('\n') + '\n');
}

function _runCli(argv) {
  const args = _parseArgv(argv);
  if (args.help) {
    _printHelp();
    return 0;
  }

  // Build initial registry to know what's available, then filter via --skip.
  const noteSink = [];
  const registry = _loadRegistry(noteSink);
  const allIds = registry.map((c) => c.id);
  const skipSet = new Set(args.skip);
  const selected = allIds.filter((id) => !skipSet.has(id));

  const envelope = runPreflight({
    projectDir: args.projectDir,
    checks: selected,
    mode: args.mode,
  });

  // Append `--skip` notes deterministically.
  for (const id of args.skip) {
    envelope.notes.push('skipped: ' + id);
  }
  envelope.notes.sort();

  if (args.mode === 'text') {
    process.stdout.write(renderText(envelope) + '\n');
  } else {
    process.stdout.write(JSON.stringify(envelope, null, 2) + '\n');
  }
  return envelope.ok ? 0 : 4;
}

if (require.main === module) {
  const code = _runCli(process.argv.slice(2));
  process.exit(code);
}

module.exports = {
  runPreflight,
  renderText,
  SCHEMA_VERSION,
  // Exposed for unit tests only; not part of the public contract.
  _loadRegistry,
  _isValidCheckModule,
  _runOneCheck,
  _parseArgv,
};

'use strict';

/**
 * branch-guard — verify current git branch matches CLAUDE.md "Expected branch" rule.
 *
 * Severity: error (blocks). If CLAUDE.md has no "Expected branch:" line, the check
 * passes with `msg: "no expected-branch rule set"` (info-grade pass).
 *
 * Pure inspection — runs `git branch --show-current` (read-only) and reads CLAUDE.md.
 */

const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');

const ID = 'branch-guard';

function _readClaudeMd(projectDir) {
  const file = path.join(projectDir, 'CLAUDE.md');
  if (!fs.existsSync(file)) return null;
  try {
    return fs.readFileSync(file, 'utf8');
  } catch (_) {
    return null;
  }
}

function _extractExpectedBranch(text) {
  if (!text) return null;
  // Match `Expected branch:` (case-insensitive), allowing markdown emphasis like `**...**`,
  // backticks around the value, optional trailing whitespace.
  const re = /expected\s*branch\s*:\s*\**\s*`?([^\s`*\n]+)`?\s*\**/i;
  const m = text.match(re);
  return m ? m[1].trim() : null;
}

function _currentBranch(projectDir) {
  // execSync is synchronous and read-only here.
  const stdout = execSync('git branch --show-current', {
    cwd: projectDir,
    encoding: 'utf8',
    stdio: ['ignore', 'pipe', 'ignore'],
  });
  return String(stdout || '').trim();
}

function run({ projectDir }) {
  const md = _readClaudeMd(projectDir);
  if (md == null) {
    return {
      ok: true,
      msg: 'no CLAUDE.md found, skipping',
    };
  }
  const expected = _extractExpectedBranch(md);
  if (!expected) {
    return {
      ok: true,
      msg: 'no expected-branch rule set',
    };
  }

  let actual;
  try {
    actual = _currentBranch(projectDir);
  } catch (err) {
    return {
      ok: false,
      msg: 'git branch --show-current failed: ' + (err && err.message || err),
      details: { expected },
    };
  }

  if (!actual) {
    return {
      ok: false,
      msg: 'detached HEAD or empty branch (expected ' + expected + ')',
      details: { expected, actual: '' },
    };
  }

  if (actual === expected) {
    return {
      ok: true,
      msg: 'on expected branch ' + expected,
      details: { expected, actual },
    };
  }

  return {
    ok: false,
    msg: 'on ' + actual + ', expected ' + expected,
    details: { expected, actual },
  };
}

module.exports = {
  id: ID,
  severity: 'error',
  run,
  // Test-only exports
  _extractExpectedBranch,
  _readClaudeMd,
  _currentBranch,
};

'use strict';

/**
 * ports-free — verify required dev ports are unbound.
 *
 * Severity: error (blocks).
 *
 * Reads `requiredFreePorts: number[]` from `.gsd-t/.unattended/config.json`.
 * If absent or empty, check is a noop pass.
 *
 * For each port, runs `lsof -nP -iTCP:<port> -sTCP:LISTEN`. Exit 0 + non-empty
 * stdout means a process is listening (FAIL). Exit 1 means no listener (PASS).
 * Anything else (lsof missing, etc.) is treated as a soft fail with note.
 */

const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');

const ID = 'ports-free';

function _readRequiredPorts(projectDir) {
  const cfgPath = path.join(projectDir, '.gsd-t', '.unattended', 'config.json');
  if (!fs.existsSync(cfgPath)) return [];
  let raw;
  try {
    raw = fs.readFileSync(cfgPath, 'utf8');
  } catch (_) {
    return [];
  }
  let parsed;
  try {
    parsed = JSON.parse(raw);
  } catch (_) {
    return [];
  }
  const ports = parsed && parsed.requiredFreePorts;
  if (!Array.isArray(ports)) return [];
  // Coerce + filter to positive integers.
  return ports
    .map((p) => Number(p))
    .filter((p) => Number.isInteger(p) && p > 0 && p < 65536);
}

function _portInUse(port) {
  // execSync throws on non-zero exit. lsof exits 1 when nothing matches.
  try {
    const stdout = execSync('lsof -nP -iTCP:' + port + ' -sTCP:LISTEN', {
      encoding: 'utf8',
      stdio: ['ignore', 'pipe', 'ignore'],
    });
    return { listening: String(stdout || '').trim().length > 0 };
  } catch (err) {
    // lsof exits 1 when no match — that's the happy "port free" path.
    if (err && err.status === 1) return { listening: false };
    // Anything else (e.g., lsof not installed) — surface as unknown.
    return { listening: false, error: err && err.message || String(err) };
  }
}

function run({ projectDir }) {
  const ports = _readRequiredPorts(projectDir);
  if (ports.length === 0) {
    return {
      ok: true,
      msg: 'no requiredFreePorts configured',
    };
  }

  const occupied = [];
  const errors = [];
  for (const port of ports) {
    const r = _portInUse(port);
    if (r.error) errors.push({ port, error: r.error });
    if (r.listening) occupied.push(port);
  }

  if (occupied.length === 0 && errors.length === 0) {
    return {
      ok: true,
      msg: 'all ' + ports.length + ' required ports are free',
      details: { ports },
    };
  }

  if (occupied.length > 0) {
    return {
      ok: false,
      msg: 'occupied ports: ' + occupied.join(', '),
      details: { ports, occupied, errors },
    };
  }

  // Only errors, no occupancy — fail closed: an error-severity check shouldn't
  // pass when we can't actually verify the ports.
  return {
    ok: false,
    msg: 'lsof probe failed for ' + errors.length + ' port(s)',
    details: { ports, errors },
  };
}

module.exports = {
  id: ID,
  severity: 'error',
  run,
  // Test-only exports
  _readRequiredPorts,
  _portInUse,
};

'use strict';

/**
 * deps-installed — verify Node deps are installed and lockfile is fresh.
 *
 * Severity: warn (records, does not block).
 *
 * Pass conditions:
 *   - `node_modules/` exists AND
 *   - `package-lock.json` mtime ≥ `package.json` mtime
 *
 * Edge cases:
 *   - No `package.json` at all → ok:true (non-Node project; nothing to check)
 *   - `package.json` exists but no `package-lock.json` → ok:false
 *   - `node_modules/` missing → ok:false
 */

const fs = require('fs');
const path = require('path');

const ID = 'deps-installed';

function _mtime(file) {
  try {
    return fs.statSync(file).mtimeMs;
  } catch (_) {
    return null;
  }
}

function run({ projectDir }) {
  const pkgPath = path.join(projectDir, 'package.json');
  const lockPath = path.join(projectDir, 'package-lock.json');
  const nmPath = path.join(projectDir, 'node_modules');

  const pkgMtime = _mtime(pkgPath);
  if (pkgMtime == null) {
    return {
      ok: true,
      msg: 'no package.json (non-Node project)',
    };
  }

  const lockMtime = _mtime(lockPath);
  const nmExists = fs.existsSync(nmPath);

  if (!nmExists && lockMtime == null) {
    return {
      ok: false,
      msg: 'node_modules/ missing AND package-lock.json missing',
      details: { nmExists, hasLock: false },
    };
  }
  if (!nmExists) {
    return {
      ok: false,
      msg: 'node_modules/ missing — run `npm install`',
      details: { nmExists: false, hasLock: lockMtime != null },
    };
  }
  if (lockMtime == null) {
    return {
      ok: false,
      msg: 'package-lock.json missing',
      details: { nmExists: true, hasLock: false },
    };
  }
  if (lockMtime < pkgMtime) {
    return {
      ok: false,
      msg: 'package-lock.json older than package.json — run `npm install`',
      details: { lockMtime, pkgMtime, ageDelta_ms: pkgMtime - lockMtime },
    };
  }

  return {
    ok: true,
    msg: 'node_modules/ present, lockfile fresh',
    details: { lockMtime, pkgMtime },
  };
}

module.exports = {
  id: ID,
  severity: 'warn',
  run,
  // Test-only exports
  _mtime,
};

'use strict';

/**
 * contracts-stable — flag DRAFT/PROPOSED contracts when project is past
 * the PARTITIONED milestone state.
 *
 * Severity: warn.
 *
 * Reads:
 *   - .gsd-t/contracts/*.md  (looking for `Status: DRAFT` or `Status: PROPOSED`)
 *   - .gsd-t/progress.md     (looking for milestone state past PARTITIONED:
 *                             ACTIVE, EXECUTING, EXECUTED, INTEGRATING, INTEGRATED,
 *                             VERIFYING, VERIFIED, COMPLETED, etc.)
 *
 * If the project is NOT past PARTITIONED, this check is a noop pass — DRAFT/PROPOSED
 * contracts are expected pre-execute. After execute starts, they should all be STABLE.
 */

const fs = require('fs');
const path = require('path');

const ID = 'contracts-stable';

// States that count as "past PARTITIONED". Anything strictly before partition
// (DEFINED, PARTITIONED itself) is fine to have DRAFT/PROPOSED contracts.
const POST_PARTITIONED_STATES = [
  'ACTIVE',
  'EXECUTING',
  'EXECUTED',
  'TEST-SYNCING',
  'TEST-SYNCED',
  'INTEGRATING',
  'INTEGRATED',
  'VERIFYING',
  'VERIFIED',
  'COMPLETED',
];

function _isPastPartitioned(progressContent) {
  if (!progressContent) return false;
  // Look for any "Status: <state>" line where state is post-partitioned.
  // Match on lines (case-insensitive); exclude comments.
  const re = /^\s*Status\s*:\s*\**\s*([A-Za-z\-]+)/gim;
  let match;
  while ((match = re.exec(progressContent)) !== null) {
    const state = match[1].toUpperCase();
    if (POST_PARTITIONED_STATES.includes(state)) return true;
  }
  return false;
}

function _scanContracts(contractsDir) {
  if (!fs.existsSync(contractsDir)) return [];
  let entries;
  try {
    entries = fs.readdirSync(contractsDir);
  } catch (_) {
    return [];
  }
  const offenders = [];
  for (const filename of entries) {
    if (!filename.endsWith('.md')) continue;
    const full = path.join(contractsDir, filename);
    let content;
    try {
      content = fs.readFileSync(full, 'utf8');
    } catch (_) {
      continue;
    }
    // Match a Status field anywhere; capture DRAFT/PROPOSED specifically.
    // Must allow markdown emphasis like `**DRAFT**` and surrounding `>` blockquotes.
    const re = /^[\s>]*Status\s*:\s*\**\s*(DRAFT|PROPOSED)\s*\**/im;
    const m = content.match(re);
    if (m) {
      offenders.push({ file: filename, status: m[1].toUpperCase() });
    }
  }
  return offenders;
}

function run({ projectDir }) {
  const contractsDir = path.join(projectDir, '.gsd-t', 'contracts');
  const progressFile = path.join(projectDir, '.gsd-t', 'progress.md');

  let progressContent = null;
  if (fs.existsSync(progressFile)) {
    try {
      progressContent = fs.readFileSync(progressFile, 'utf8');
    } catch (_) {
      progressContent = null;
    }
  }

  const offenders = _scanContracts(contractsDir);
  const past = _isPastPartitioned(progressContent);

  if (!past) {
    return {
      ok: true,
      msg: 'project not past PARTITIONED; ' + offenders.length + ' DRAFT/PROPOSED contract(s) acceptable',
      details: { offenders },
    };
  }

  if (offenders.length === 0) {
    return {
      ok: true,
      msg: 'all contracts STABLE',
    };
  }

  return {
    ok: false,
    msg: offenders.length + ' DRAFT/PROPOSED contract(s) past PARTITIONED: ' +
      offenders.map((o) => o.file + '(' + o.status + ')').join(', '),
    details: { offenders },
  };
}

module.exports = {
  id: ID,
  severity: 'warn',
  run,
  // Test-only exports
  _isPastPartitioned,
  _scanContracts,
  POST_PARTITIONED_STATES,
};

'use strict';

/**
 * manifest-fresh — verify .gsd-t/journey-manifest.json is newer than every
 * file under e2e/journeys/.
 *
 * Severity: info. Never blocks (top-level `ok` only flips on error-severity).
 *
 * If the manifest or the e2e/journeys/ dir is missing, the check is an
 * info-grade noop pass with `msg: "no manifest, skipping"`.
 */

const fs = require('fs');
const path = require('path');

const ID = 'manifest-fresh';

function _walkSync(dir, out) {
  let entries;
  try {
    entries = fs.readdirSync(dir, { withFileTypes: true });
  } catch (_) {
    return;
  }
  for (const e of entries) {
    const full = path.join(dir, e.name);
    if (e.isDirectory()) {
      _walkSync(full, out);
    } else if (e.isFile()) {
      out.push(full);
    }
  }
}

function _mtime(file) {
  try {
    return fs.statSync(file).mtimeMs;
  } catch (_) {
    return null;
  }
}

function run({ projectDir }) {
  const manifestPath = path.join(projectDir, '.gsd-t', 'journey-manifest.json');
  const journeysDir = path.join(projectDir, 'e2e', 'journeys');

  const manifestMtime = _mtime(manifestPath);
  const journeysExists = fs.existsSync(journeysDir);

  if (manifestMtime == null || !journeysExists) {
    return {
      ok: true,
      msg: 'no manifest, skipping',
    };
  }

  const files = [];
  _walkSync(journeysDir, files);

  if (files.length === 0) {
    return {
      ok: true,
      msg: 'manifest present, no journey files to compare',
    };
  }

  const stale = [];
  for (const f of files) {
    const m = _mtime(f);
    if (m == null) continue;
    if (m > manifestMtime) {
      stale.push({ file: path.relative(projectDir, f), mtime: m });
    }
  }

  if (stale.length === 0) {
    return {
      ok: true,
      msg: 'manifest fresher than ' + files.length + ' journey file(s)',
      details: { manifestMtime, scanned: files.length },
    };
  }

  return {
    ok: false,
    msg: 'manifest stale: ' + stale.length + ' journey file(s) newer',
    details: { manifestMtime, stale, scanned: files.length },
  };
}

module.exports = {
  id: ID,
  severity: 'info',
  run,
  // Test-only exports
  _walkSync,
  _mtime,
};

'use strict';

/**
 * working-tree-state — git working tree clean or matches dirtyTreeWhitelist.
 *
 * Severity: warn.
 *
 * Reads `dirtyTreeWhitelist: string[]` from `.gsd-t/.unattended/config.json`.
 * Each dirty path from `git status --porcelain` must match the whitelist for
 * the check to pass. Whitelist patterns use simple glob:
 *   - `**`  matches any sequence of characters (including `/`)
 *   - `*`   matches any non-`/` segment
 *   - everything else is literal
 *
 * If the working tree is clean, the check passes with no whitelist consulted.
 */

const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');

const ID = 'working-tree-state';

function _readWhitelist(projectDir) {
  const cfgPath = path.join(projectDir, '.gsd-t', '.unattended', 'config.json');
  if (!fs.existsSync(cfgPath)) return [];
  let raw;
  try { raw = fs.readFileSync(cfgPath, 'utf8'); } catch (_) { return []; }
  let parsed;
  try { parsed = JSON.parse(raw); } catch (_) { return []; }
  const list = parsed && parsed.dirtyTreeWhitelist;
  if (!Array.isArray(list)) return [];
  return list.filter((s) => typeof s === 'string' && s.length > 0);
}

function _porcelain(projectDir) {
  const stdout = execSync('git status --porcelain', {
    cwd: projectDir,
    encoding: 'utf8',
    stdio: ['ignore', 'pipe', 'ignore'],
  });
  return String(stdout || '');
}

function _parseDirtyPaths(porcelain) {
  // `git status --porcelain` output: "XY path" or "XY path1 -> path2" (rename).
  // We take the (final) path; X/Y are status codes.
  const out = [];
  const lines = porcelain.split(/\r?\n/);
  for (const line of lines) {
    if (!line || line.length < 4) continue;
    let rest = line.slice(3);
    // Handle quoted paths from git (when path contains special chars).
    if (rest.startsWith('"') && rest.endsWith('"')) {
      rest = rest.slice(1, -1).replace(/\\"/g, '"').replace(/\\\\/g, '\\');
    }
    // Handle rename: "old -> new"
    const renameIdx = rest.indexOf(' -> ');
    if (renameIdx >= 0) rest = rest.slice(renameIdx + 4);
    out.push(rest);
  }
  return out;
}

function _globToRegex(glob) {
  // Escape regex specials except `*`, then expand `*` semantics.
  // Use a placeholder dance so `**` becomes `.*` and `*` becomes `[^/]*`.
  let s = '';
  let i = 0;
  while (i < glob.length) {
    const ch = glob[i];
    if (ch === '*' && glob[i + 1] === '*') {
      s += '.*';
      i += 2;
      // Swallow optional trailing slash so `foo/**` matches `foo/anything`
      // and also exactly `foo` is NOT matched (whitelisting expects the dir
      // contents). Simpler semantic: just .* — caller can decide.
      continue;
    }
    if (ch === '*') {
      s += '[^/]*';
      i++;
      continue;
    }
    if (/[.+^${}()|[\]\\?]/.test(ch)) {
      s += '\\' + ch;
      i++;
      continue;
    }
    s += ch;
    i++;
  }
  return new RegExp('^' + s + '$');
}

function _matchesAny(p, patterns) {
  for (const pat of patterns) {
    if (_globToRegex(pat).test(p)) return true;
  }
  return false;
}

function run({ projectDir }) {
  let porcelain;
  try {
    porcelain = _porcelain(projectDir);
  } catch (err) {
    return {
      ok: false,
      msg: 'git status failed: ' + (err && err.message || err),
    };
  }
  const dirty = _parseDirtyPaths(porcelain);
  if (dirty.length === 0) {
    return { ok: true, msg: 'working tree clean' };
  }

  const whitelist = _readWhitelist(projectDir);
  const unmatched = dirty.filter((p) => !_matchesAny(p, whitelist));

  if (unmatched.length === 0) {
    return {
      ok: true,
      msg: 'working tree dirty (' + dirty.length + ' path(s)) but all whitelisted',
      details: { dirty: dirty.length, whitelisted: dirty.length },
    };
  }

  return {
    ok: false,
    msg: unmatched.length + ' dirty path(s) outside whitelist',
    details: {
      dirty: dirty.length,
      unmatched,
      whitelist,
    },
  };
}

module.exports = {
  id: ID,
  severity: 'warn',
  run,
  // Test-only exports
  _readWhitelist,
  _parseDirtyPaths,
  _globToRegex,
  _matchesAny,
};

