function _extractExpectedBranch(text) {
  if (!text) return null;
  // Match `Expected branch:` (case-insensitive), allowing markdown emphasis like `**...**`,
  // backticks around the value, optional trailing whitespace.
  const re = /expected\s*branch\s*:\s*\**\s*`?([^\s`*\n]+)`?\s*\**/i;
  const m = text.match(re);
  return m ? m[1].trim() : null;
}

