252	function _computeLastSpawnAt(spawnPlans) {
253	  let best = null;
254	  for (const p of spawnPlans) {
255	    const s = _safeDate(p && p.startedAt);
256	    if (!s) continue;
257	    if (!best || s.getTime() > best.getTime()) best = s;
258	  }
259	  return best ? best.toISOString() : null;
260	}
