289	
290	  let total = 0;
291	  for (const name of domainNames) {
292	    const tasksFile = path.join(domainsDir, name, 'tasks.md');
293	    if (!fs.existsSync(tasksFile)) continue;
294	    let content;
295	    try {
296	      content = fs.readFileSync(tasksFile, 'utf8');
297	    } catch (err) {
298	      notes.push('tasks.md read failed: ' + tasksFile);
