301	    // Count pending tasks: bullets starting with `- [ ]` (Shape A/C) OR `### Mxx-Dx-Tx` with no `[x]`.
302	    // For D9's purposes we count `- [ ]` markers — matches the existing task-graph parser.
303	    const lines = content.split(/\r?\n/);
