314	function _computeGateDecisions(projectDir, now, notes) {
315	  const eventsDir = path.join(projectDir, '.gsd-t', 'events');
316	  const out = {
317	    dep_gate_veto: { count: 0, last_reasons: [] },
318	    disjointness_fallback: { count: 0, last_reasons: [] },
319	    economics_decision: { count: 0, confidence_distribution: { HIGH: 0, MEDIUM: 0, LOW: 0, FALLBACK: 0 } },
320	  };
321	  if (!fs.existsSync(eventsDir)) return out;
322	
323	  // Read last 14 days of events.
324	  const days = [];
325	  for (let i = 0; i < 14; i++) {
326	    const d = new Date(now.getTime() - i * 86400000);
327	    const iso = d.toISOString().slice(0, 10);
328	    days.push(iso);
329	  }
330	
331	  const rows = [];
332	  for (const day of days) {
333	    const f = path.join(eventsDir, day + '.jsonl');
334	    if (!fs.existsSync(f)) continue;
335	    let content;
336	    try {
337	      content = fs.readFileSync(f, 'utf8');
338	    } catch (err) {
339	      notes.push('events file unreadable: ' + f);
340	      continue;
341	    }
342	    const lines = content.split(/\r?\n/).filter((l) => l.length > 0);
343	    for (const line of lines) {
344	      let obj;
345	      try { obj = JSON.parse(line); }
346	      catch (_) { continue; }
347	      if (!obj || typeof obj !== 'object') continue;
348	      rows.push(obj);
349	    }
350	  }
351	
352	  // Sort by ts ascending; take last 10 of each type.
353	  rows.sort((a, b) => String(a.ts || '').localeCompare(String(b.ts || '')));
354	
355	  const depRows = rows.filter((r) => r.type === 'dep_gate_veto').slice(-10);
356	  const disRows = rows.filter((r) => r.type === 'disjointness_fallback').slice(-10);
357	  const ecoRows = rows.filter((r) => r.type === 'economics_decision').slice(-10);
358	
359	  out.dep_gate_veto.count = depRows.length;
360	  out.dep_gate_veto.last_reasons = depRows.map((r) => r.reason || r.task_id || '—').slice(-5);
361	
362	  out.disjointness_fallback.count = disRows.length;
363	  out.disjointness_fallback.last_reasons = disRows.map((r) => r.reason || r.task_id || '—').slice(-5);
364	
365	  out.economics_decision.count = ecoRows.length;
366	  for (const r of ecoRows) {
367	    const c = String(r.confidence || 'FALLBACK').toUpperCase();
368	    if (Object.prototype.hasOwnProperty.call(out.economics_decision.confidence_distribution, c)) {
369	      out.economics_decision.confidence_distribution[c]++;
370	    } else {
371	      out.economics_decision.confidence_distribution.FALLBACK++;
372	    }
373	  }
374	
375	  return out;
376	}
