413	function _computeColorState({ activeWorkers, readyTasks, gate, factor, activeSpawnAges_s, lastSpawnAt, now, noSpawns }) {
414	  if (noSpawns) return 'dimmed';
415	
416	  const signals = [];
417	
418	  // Signal 1: activeWorkers vs readyTasks
419	  if (readyTasks > 0) {
420	    const ratio = activeWorkers / readyTasks;
421	    const lastSpawn = _safeDate(lastSpawnAt);
422	    const minutesSinceSpawn = lastSpawn
423	      ? (now.getTime() - lastSpawn.getTime()) / 60000
424	      : Infinity;
425	    if (ratio >= 0.8) signals.push('green');
426	    else if (ratio >= 0.5) signals.push('yellow');
427	    else if (minutesSinceSpawn > 10) signals.push('red');
428	    else signals.push('yellow');
429	  }
430	
431	  // Signal 2: gate veto rate (dep_gate_veto count vs. total gate events)
432	  const totalGate = gate.dep_gate_veto.count + gate.disjointness_fallback.count + gate.economics_decision.count;
433	  if (totalGate > 0) {
434	    const vetoRate = gate.dep_gate_veto.count / totalGate;
435	    if (vetoRate < 0.1) signals.push('green');
436	    else if (vetoRate <= 0.3) signals.push('yellow');
437	    else signals.push('red');
438	  }
439	
440	  // Signal 3: parallelism_factor vs. ideal (use activeWorkers as ideal — D6 estimate not yet wired)
441	  if (factor.mode === 'live' && activeWorkers > 1) {
442	    const ideal = activeWorkers;
443	    const ratio = factor.value / ideal;
444	    if (ratio >= 0.8) signals.push('green');
445	    else if (ratio >= 0.5) signals.push('yellow');
446	    else signals.push('red');
447	  }
448	
449	  // Signal 4: spawn age (any active > 45 min = red, 30-45 yellow)
450	  if (activeSpawnAges_s.length > 0) {
451	    const maxAge_m = activeSpawnAges_s[0] / 60;
452	    if (maxAge_m < 30) signals.push('green');
453	    else if (maxAge_m <= 45) signals.push('yellow');
454	    else signals.push('red');
455	  }
456	
457	  // Signal 5: time since last spawn_started when ready>0
458	  if (readyTasks > 0) {
459	    const lastSpawn = _safeDate(lastSpawnAt);
460	    const minutesSinceSpawn = lastSpawn
461	      ? (now.getTime() - lastSpawn.getTime()) / 60000
462	      : Infinity;
463	    if (minutesSinceSpawn < 5) signals.push('green');
464	    else if (minutesSinceSpawn <= 10) signals.push('yellow');
465	    else signals.push('red');
466	  }
467	
468	  if (signals.length === 0) return 'green';
469	  if (signals.includes('red')) return 'red';
470	  if (signals.includes('yellow')) return 'yellow';
471	  return 'green';
472	}
473	
474	function _renderAsciiGantt(spawns, now) {
475	  if (spawns.length === 0) return '(no spawns in this wave)';
476	  const valid = spawns
477	    .map((p) => {
478	      const s = _safeDate(p.startedAt);
479	      if (!s) return null;
480	      const e = p.endedAt ? _safeDate(p.endedAt) : now;
481	      if (!e) return null;
482	      return { id: p.spawnId || '—', start: s.getTime(), end: e.getTime() };
483	    })
484	    .filter(Boolean);
485	  if (!valid.length) return '(no datable spawns)';
486	
487	  const minStart = Math.min(...valid.map((v) => v.start));
488	  const maxEnd = Math.max(...valid.map((v) => v.end));
489	  const span = Math.max(1, maxEnd - minStart);
490	  const WIDTH = 60;
491	
492	  const lines = [];
493	  lines.push('t=0' + ' '.repeat(WIDTH - 3) + 't=' + Math.floor(span / 1000) + 's');
494	  for (const v of valid) {
495	    const startCol = Math.floor(((v.start - minStart) / span) * WIDTH);
496	    const endCol = Math.floor(((v.end - minStart) / span) * WIDTH);
497	    const bar = ' '.repeat(startCol) + '#'.repeat(Math.max(1, endCol - startCol)) + ' '.repeat(Math.max(0, WIDTH - endCol));
498	    const id = (v.id || '—').slice(0, 24).padEnd(24);
499	    lines.push(id + ' |' + bar + '|');
500	  }
501	  return lines.join('\n');
502	}
