31	/**
32	 * @param {object} [opts]
33	 * @param {string} [opts.projectDir='.']
34	 * @param {string[]} [opts.checks]   restrict to these check ids (default = all built-ins)
35	 * @param {string} [opts.mode='json'] informational; envelope is identical
36	 * @returns {{ ok: boolean, schemaVersion: string, checks: object[], notes: string[] }}
37	 */
38	function runPreflight(opts) {
39	  opts = opts || {};
40	  const projectDir = opts.projectDir || '.';
41	  const restrict = Array.isArray(opts.checks) ? new Set(opts.checks) : null;
42	  const notes = [];
43	
44	  const registry = _loadRegistry(notes);
45	
46	  const selected = restrict
47	    ? registry.filter((c) => restrict.has(c.id))
48	    : registry;
49	
50	  const checkResults = [];
51	  for (const check of selected) {
52	    const result = _runOneCheck(check, { projectDir }, notes);
53	    checkResults.push(result);
54	  }
55	
56	  // Sort checks by id, ascending. Sort notes ascending.
57	  checkResults.sort((a, b) => (a.id < b.id ? -1 : a.id > b.id ? 1 : 0));
