80	  for (const c of envelope.checks) {
81	    const icon = c.ok ? '✓' : (c.severity === 'error' ? '✗' : '!');
82	    lines.push('  ' + icon + ' [' + c.severity.padEnd(5) + '] ' + c.id + ' — ' + c.msg);
83	  }
84	  if (envelope.notes && envelope.notes.length) {
85	    lines.push('');
86	    lines.push('Notes:');
