202	    '',
203	    'Options:',
204	    '  --project DIR     Project root (default: .)',
205	    '  --json            Print JSON envelope (default)',
206	    '  --text            Print human-readable summary',
207	    '  --skip id1,id2    Skip listed checks (each appends a note)',
208	    '  --help            Show this help',
209	    '',
210	    'Exit codes:',
211	    '  0  preflight ok',
212	    '  4  preflight failed (>=1 error-severity check failed)',
213	  ];
214	  process.stdout.write(lines.join('\n') + '\n');
