'use strict';

/**
 * GSD-T Context Brief Generator (M55 D4)
 *
 * Pluggable, deterministic, zero-dep context-brief library + thin CLI.
 *
 * Pure inspector — no LLM spawn, no token spend, no side effects beyond reading
 * the filesystem, running read-only `git` commands inside per-kind collectors,
 * and (optionally) writing the resulting brief JSON to `--out`.
 *
 * Contract: .gsd-t/contracts/context-brief-contract.md v1.0.0 STABLE.
 *
 * Hard rules (mirroring bin/cli-preflight.cjs / bin/parallelism-report.cjs):
 *   1. Zero external runtime deps. Only Node built-ins.
 *   2. Synchronous public API.
 *   3. Per-kind throws are caught and surface as a structured error.
 *   4. Deterministic output — sorted arrays, alphabetical JSON keys.
 *   5. captureSpawn-exempt — see contract § captureSpawn Exemption.
 */

const fs = require('fs');
const path = require('path');

const SCHEMA_VERSION = '1.0.0';
const MAX_BRIEF_BYTES = 10240;
const KINDS_DIR_NAME = 'gsd-t-context-brief-kinds';
const SAFE_NAME_RE = /^[a-zA-Z0-9_-]+$/;

const FAIL_CLOSED_KINDS = new Set(['qa', 'red-team', 'design-verify']);

// ── Public API ──────────────────────────────────────────────────────────────

/**
 * Synchronously assemble a context brief.
 *
 * @param {object} opts
 * @param {string} opts.projectDir
 * @param {string} opts.kind        one of KINDS
 * @param {string|null} [opts.domain]
 * @param {string} opts.spawnId
 * @param {boolean} [opts.strict=false]   upgrade fail-open kinds to fail-closed
 * @param {Date} [opts.now]               injected for tests / determinism
 * @returns {object} brief envelope
 */
function generateBrief(opts) {
  if (!opts || typeof opts !== 'object') {
    throw new Error('generateBrief: opts required');
  }
  const projectDir = typeof opts.projectDir === 'string' && opts.projectDir.length
    ? opts.projectDir
    : '.';
  const kind = opts.kind;
  const domain = (typeof opts.domain === 'string' && opts.domain.length) ? opts.domain : null;
  const spawnId = opts.spawnId;
  const strict = !!opts.strict;
  const now = opts.now instanceof Date ? opts.now : new Date();

  if (typeof kind !== 'string' || !kind.length) {
    throw new Error('generateBrief: kind required');
  }
  if (typeof spawnId !== 'string' || !spawnId.length) {
    throw new Error('generateBrief: spawnId required');
  }
  if (!SAFE_NAME_RE.test(spawnId)) {
    throw new Error('generateBrief: spawnId contains unsafe characters (allowed: [a-zA-Z0-9_-])');
  }
  if (domain != null && !SAFE_NAME_RE.test(domain)) {
    throw new Error('generateBrief: domain contains unsafe characters (allowed: [a-zA-Z0-9_-])');
  }

  const registry = loadKindRegistry();
  const kindMod = registry.find((k) => k.name === kind);
  if (!kindMod) {
    throw new Error('generateBrief: unknown kind "' + kind + '" (known: ' +
      registry.map((k) => k.name).sort().join(',') + ')');
  }

  // sourceMtimes is gathered via the recorder helper passed into the collector.
  const sourceMtimes = {};
  function recordSource(relPath) {
    if (typeof relPath !== 'string' || !relPath.length) return null;
    const full = path.join(projectDir, relPath);
    let stat;
    try { stat = fs.statSync(full); } catch (_) { return null; }
    sourceMtimes[relPath] = new Date(stat.mtimeMs).toISOString();
    return stat;
  }

  // Required-source check (fail-closed kinds)
  const missingRequired = [];
  for (const req of (kindMod.requiresSources || [])) {
    const full = path.join(projectDir, req);
    if (!fs.existsSync(full)) missingRequired.push(req);
  }
  const isFailClosedKind = FAIL_CLOSED_KINDS.has(kind);
  if (missingRequired.length && (isFailClosedKind || strict)) {
    const err = new Error('generateBrief: required source(s) missing for kind=' + kind +
      ': ' + missingRequired.sort().join(', '));
    err.code = 'EREQUIRED_MISSING';
    err.missing = missingRequired.slice().sort();
    throw err;
  }

  let collected;
  try {
    collected = kindMod.collect({
      projectDir,
      kind,
      domain,
      spawnId,
      strict,
      recordSource,
    });
  } catch (err) {
    const wrapped = new Error('generateBrief: kind "' + kind + '" collector threw: ' +
      (err && err.message || String(err)));
    wrapped.cause = err;
    throw wrapped;
  }

  if (!collected || typeof collected !== 'object') {
    throw new Error('generateBrief: kind "' + kind + '" collector returned non-object');
  }

  // Branch detection (read-only). Captured at the library level, not per-kind,
  // so all briefs share a uniform branch field.
  const branch = _gitCurrentBranch(projectDir);

  const brief = {
    ancillary: _normalizeAncillary(collected.ancillary),
    branch: branch || '',
    constraints: _normalizeConstraints(collected.constraints),
    contracts: _normalizeContracts(collected.contracts),
    domain,
    generatedAt: now.toISOString(),
    kind,
    schemaVersion: SCHEMA_VERSION,
    scope: _normalizeScope(collected.scope),
    sourceMtimes: _sortObjectKeys(sourceMtimes),
    spawnId,
  };

  // Hard cap enforcement at write-time.
  const serialized = stableStringify(brief);
  if (Buffer.byteLength(serialized, 'utf8') > MAX_BRIEF_BYTES) {
    const err = new Error('brief exceeds MAX_BRIEF_BYTES (' + Buffer.byteLength(serialized, 'utf8') +
      ' > ' + MAX_BRIEF_BYTES + ')');
    err.code = 'EBRIEF_TOO_LARGE';
    throw err;
  }

  return brief;
}

/**
 * Discover and load all kind collector modules from
 * `bin/gsd-t-context-brief-kinds/*.cjs`.
 * @returns {Array<{name:string, requiresSources:string[], collect:Function}>}
 */
function loadKindRegistry() {
  const dir = path.join(__dirname, KINDS_DIR_NAME);
  let entries;
  try {
    entries = fs.readdirSync(dir);
  } catch (_) {
    return [];
  }
  const out = [];
  for (const filename of entries) {
    if (!filename.endsWith('.cjs')) continue;
    const full = path.join(dir, filename);
    let mod;
    try { mod = require(full); } catch (_) { continue; }
    if (!_isValidKindModule(mod, filename)) continue;
    out.push(mod);
  }
  out.sort((a, b) => (a.name < b.name ? -1 : a.name > b.name ? 1 : 0));
  return out;
}

const KINDS = ['design-verify', 'execute', 'qa', 'red-team', 'scan', 'verify'];

/**
 * Deterministic JSON stringifier — alphabetical keys at every nesting level,
 * arrays preserved in caller-supplied order. Used by `generateBrief` for
 * cap-check and by the test suite for byte-identical assertions.
 * @param {*} value
 * @returns {string}
 */
function stableStringify(value) {
  return JSON.stringify(_canonicalize(value), null, 2);
}

// ── Internal helpers ────────────────────────────────────────────────────────

function _isValidKindModule(mod, filename) {
  if (!mod || typeof mod !== 'object') return false;
  if (typeof mod.name !== 'string' || !mod.name.length) return false;
  if (typeof mod.collect !== 'function') return false;
  if (mod.requiresSources != null && !Array.isArray(mod.requiresSources)) return false;
  // filename stem must match name
  const stem = filename.replace(/\.cjs$/, '');
  if (stem !== mod.name) return false;
  return true;
}

function _gitCurrentBranch(projectDir) {
  try {
    const { execSync } = require('child_process');
    const stdout = execSync('git branch --show-current', {
      cwd: projectDir,
      encoding: 'utf8',
      stdio: ['ignore', 'pipe', 'ignore'],
    });
    return String(stdout || '').trim();
  } catch (_) {
    return '';
  }
}

function _normalizeScope(scope) {
  const s = scope && typeof scope === 'object' ? scope : {};
  return {
    deliverables: _sortStringArray(s.deliverables),
    notOwned: _sortStringArray(s.notOwned),
    owned: _sortStringArray(s.owned),
  };
}

function _normalizeConstraints(c) {
  return _sortStringArray(c);
}

function _normalizeContracts(arr) {
  if (!Array.isArray(arr)) return [];
  const out = [];
  for (const item of arr) {
    if (!item || typeof item !== 'object') continue;
    out.push({
      path: typeof item.path === 'string' ? item.path : '',
      status: typeof item.status === 'string' ? item.status : 'UNKNOWN',
    });
  }
  out.sort((a, b) => (a.path < b.path ? -1 : a.path > b.path ? 1 : 0));
  return out;
}

function _normalizeAncillary(a) {
  if (!a || typeof a !== 'object') return {};
  // Recursively canonicalize ancillary objects so JSON is deterministic.
  return _canonicalize(a);
}

function _sortStringArray(arr) {
  if (!Array.isArray(arr)) return [];
  const xs = arr.filter((v) => typeof v === 'string');
  xs.sort();
  return xs;
}

function _sortObjectKeys(obj) {
  if (!obj || typeof obj !== 'object' || Array.isArray(obj)) return obj;
  const out = {};
  for (const k of Object.keys(obj).sort()) out[k] = obj[k];
  return out;
}

function _canonicalize(v) {
  if (v == null) return v;
  if (Array.isArray(v)) return v.map(_canonicalize);
  if (typeof v === 'object') {
    const out = {};
    for (const k of Object.keys(v).sort()) out[k] = _canonicalize(v[k]);
    return out;
  }
  return v;
}

// ── CLI ─────────────────────────────────────────────────────────────────────

function _parseArgv(argv) {
  const out = { projectDir: '.', mode: 'json', strict: false };
  for (let i = 0; i < argv.length; i++) {
    const a = argv[i];
    if (a === '--kind') out.kind = argv[++i];
    else if (a === '--domain') out.domain = argv[++i];
    else if (a === '--spawn-id') out.spawnId = argv[++i];
    else if (a === '--out') out.out = argv[++i];
    else if (a === '--project') out.projectDir = argv[++i] || '.';
    else if (a === '--json') out.mode = 'json';
    else if (a === '--strict') out.strict = true;
    else if (a === '--help' || a === '-h') out.help = true;
  }
  return out;
}

function _printHelp(stream) {
  const lines = [
    'Usage: node bin/gsd-t-context-brief.cjs --kind X --spawn-id Y [options]',
    '',
    'Options:',
    '  --kind X          one of: execute|verify|qa|red-team|design-verify|scan',
    '  --domain Y        domain id, [a-zA-Z0-9_-]+ (required for execute/verify/qa/red-team)',
    '  --spawn-id Z      spawn id, [a-zA-Z0-9_-]+ (required)',
    '  --out PATH        write brief to file (default: stdout)',
    '  --json            JSON output to stdout (default)',
    '  --strict          fail-closed on any missing source',
    '  --project DIR     project root (default: .)',
    '  --help, -h        show this help',
    '',
    'Exit codes:',
    '  0  brief generated',
    '  2  CLI usage error / path-safety reject',
    '  4  required source missing OR --strict missing source OR over-cap',
  ];
  (stream || process.stdout).write(lines.join('\n') + '\n');
}

function _runCli(argv) {
  const args = _parseArgv(argv);
  if (args.help) { _printHelp(); return 0; }

  if (typeof args.kind !== 'string' || !args.kind.length) {
    process.stderr.write('error: --kind is required\n');
    return 2;
  }
  if (typeof args.spawnId !== 'string' || !args.spawnId.length) {
    process.stderr.write('error: --spawn-id is required\n');
    return 2;
  }
  if (!SAFE_NAME_RE.test(args.spawnId)) {
    process.stderr.write('error: --spawn-id must match [a-zA-Z0-9_-]+ (got: ' + JSON.stringify(args.spawnId) + ')\n');
    return 2;
  }
  if (args.domain != null && !SAFE_NAME_RE.test(args.domain)) {
    process.stderr.write('error: --domain must match [a-zA-Z0-9_-]+ (got: ' + JSON.stringify(args.domain) + ')\n');
    return 2;
  }

  let brief;
  try {
    brief = generateBrief({
      projectDir: args.projectDir,
      kind: args.kind,
      domain: args.domain || null,
      spawnId: args.spawnId,
      strict: args.strict,
    });
  } catch (err) {
    process.stderr.write('error: ' + (err && err.message || String(err)) + '\n');
    if (err && (err.code === 'EREQUIRED_MISSING' || err.code === 'EBRIEF_TOO_LARGE')) return 4;
    // Unknown-kind / unsafe-input / other usage errors → exit 2.
    if (err && /unsafe|required|unknown|spawnId|domain/i.test(err.message)) return 2;
    return 4;
  }

  const json = stableStringify(brief);
  if (args.out) {
    try {
      fs.mkdirSync(path.dirname(args.out), { recursive: true });
      fs.writeFileSync(args.out, json + '\n');
    } catch (err) {
      process.stderr.write('error: failed to write --out: ' + (err && err.message || err) + '\n');
      return 4;
    }
  } else {
    process.stdout.write(json + '\n');
  }
  return 0;
}

if (require.main === module) {
  const code = _runCli(process.argv.slice(2));
  process.exit(code);
}

module.exports = {
  generateBrief,
  loadKindRegistry,
  stableStringify,
  SCHEMA_VERSION,
  MAX_BRIEF_BYTES,
  KINDS,
  // Test-only exports
  _parseArgv,
  _isValidKindModule,
  _canonicalize,
  _gitCurrentBranch,
  SAFE_NAME_RE,
  FAIL_CLOSED_KINDS,
};

'use strict';

/**
 * execute kind collector — pulls domain scope/constraints/tasks/contracts
 * for a single domain so an execute-phase worker can grep the brief
 * instead of re-walking the repo.
 *
 * Fail-open: if the domain dir is missing, scope/constraints/contracts
 * are empty arrays — the brief is still written.
 */

const fs = require('fs');
const path = require('path');

const NAME = 'execute';

function _readMaybe(file) {
  try { return fs.readFileSync(file, 'utf8'); } catch (_) { return null; }
}

/**
 * Extract bullet items under a `## Heading` (non-greedy, until the next `## ` or EOF).
 */
function _bulletsUnderSection(text, headingPattern) {
  if (!text) return [];
  const re = new RegExp('^##\\s+' + headingPattern + '\\s*$([\\s\\S]*?)(?=^##\\s+|\\Z)', 'mi');
  const m = text.match(re);
  if (!m) return [];
  const body = m[1];
  const out = [];
  for (const line of body.split(/\r?\n/)) {
    const t = line.trim();
    // Match `- foo`, `* foo`, `- **bar**` — strip leading bullet + inline backticks/asterisks.
    const bm = t.match(/^[-*]\s+(.+)$/);
    if (!bm) continue;
    let item = bm[1].replace(/`/g, '').replace(/\*\*/g, '').trim();
    // Truncate very long bullets (fits cap budget).
    if (item.length > 240) item = item.slice(0, 237) + '...';
    out.push(item);
  }
  return out;
}

/**
 * Extract a path glob list from "Owned Files/Directories" section bullets,
 * keeping only the leading code-fence path before any em-dash.
 */
function _ownedPathsFromScope(text) {
  if (!text) return [];
  const re = /^##\s+Owned Files\/Directories\s*$([\s\S]*?)(?=^##\s+|\Z)/mi;
  const m = text.match(re);
  if (!m) return [];
  const out = [];
  for (const line of m[1].split(/\r?\n/)) {
    const bm = line.match(/^\s*[-*]\s+`([^`]+)`/);
    if (bm) out.push(bm[1]);
  }
  return out;
}

function _notOwnedPaths(text) {
  if (!text) return [];
  const re = /^##\s+NOT Owned[^\n]*$([\s\S]*?)(?=^##\s+|\Z)/mi;
  const m = text.match(re);
  if (!m) return [];
  const out = [];
  for (const line of m[1].split(/\r?\n/)) {
    const bm = line.match(/^\s*[-*]\s+`([^`]+)`/);
    if (bm) out.push(bm[1]);
  }
  return out;
}

/**
 * Collect contract paths referenced from inside the scope text — pattern
 * `.gsd-t/contracts/<name>.md`.
 */
function _contractsReferenced(text, projectDir) {
  if (!text) return [];
  const re = /\.gsd-t\/contracts\/[a-zA-Z0-9_./-]+\.md/g;
  const seen = new Set();
  const out = [];
  let m;
  while ((m = re.exec(text)) != null) {
    const p = m[0];
    if (seen.has(p)) continue;
    seen.add(p);
    let status = 'UNKNOWN';
    const full = path.join(projectDir, p);
    try {
      const c = fs.readFileSync(full, 'utf8');
      const sm = c.match(/Status:\s*\**\s*(STABLE|DRAFT|PROPOSED)/i);
      if (sm) status = sm[1].toUpperCase();
    } catch (_) { /* fail-open */ }
    out.push({ path: p, status });
  }
  return out;
}

/**
 * Extract the task ids ("T1", "T-2", "M55-D4-T3", …) from tasks.md.
 */
function _tasksFromTasksMd(text) {
  if (!text) return [];
  const out = [];
  // ## T1 — heading
  const reH = /^##\s+(T-?\d+)\b[^\n]*$/gm;
  let m;
  while ((m = reH.exec(text)) != null) out.push(m[1]);
  // ### M{NN}-D{N}-T{N} headings (Shape C)
  const reC = /^###\s+(M\d+-D\d+-T\d+)\b[^\n]*$/gm;
  while ((m = reC.exec(text)) != null) out.push(m[1]);
  // - [ ] **M55-D4-T1** (Shape C bullets)
  const reBC = /^\s*-\s*\[[ x]\]\s+\*\*(M\d+-D\d+-T\d+)\*\*/gm;
  while ((m = reBC.exec(text)) != null) out.push(m[1]);
  return out;
}

function collect(ctx) {
  const { projectDir, domain, recordSource } = ctx;
  const ancillary = {
    expectedOutputs: [],
    filesOwned: [],
    notOwned: [],
    tasks: [],
  };
  let scope = { owned: [], notOwned: [], deliverables: [] };
  let constraints = [];
  let contracts = [];

  if (!domain) {
    return { scope, constraints, contracts, ancillary };
  }

  const dir = path.join(projectDir, '.gsd-t', 'domains', domain);
  if (!fs.existsSync(dir)) {
    // Fail-open: domain dir absent → empty fields.
    return { scope, constraints, contracts, ancillary };
  }

  const scopePath = '.gsd-t/domains/' + domain + '/scope.md';
  const constraintsPath = '.gsd-t/domains/' + domain + '/constraints.md';
  const tasksPath = '.gsd-t/domains/' + domain + '/tasks.md';

  const scopeText = _readMaybe(path.join(projectDir, scopePath));
  if (scopeText) recordSource(scopePath);
  const constraintsText = _readMaybe(path.join(projectDir, constraintsPath));
  if (constraintsText) recordSource(constraintsPath);
  const tasksText = _readMaybe(path.join(projectDir, tasksPath));
  if (tasksText) recordSource(tasksPath);

  const owned = _ownedPathsFromScope(scopeText);
  const notOwned = _notOwnedPaths(scopeText);
  const deliverables = _bulletsUnderSection(scopeText, 'Deliverables');

  scope = { owned, notOwned, deliverables };

  const mustFollow = _bulletsUnderSection(constraintsText, 'Must Follow');
  const mustNot = _bulletsUnderSection(constraintsText, 'Must Not');
  // Mark items by prefix so the worker can tell them apart.
  constraints = mustFollow.map((c) => 'MUST: ' + c).concat(mustNot.map((c) => 'MUST NOT: ' + c));

  contracts = _contractsReferenced(scopeText, projectDir);

  const tasks = _tasksFromTasksMd(tasksText);

  ancillary.filesOwned = owned;
  ancillary.notOwned = notOwned;
  ancillary.expectedOutputs = deliverables;
  ancillary.tasks = tasks;

  return { scope, constraints, contracts, ancillary };
}

module.exports = {
  name: NAME,
  requiresSources: [],
  collect,
  // Test-only exports
  _bulletsUnderSection,
  _ownedPathsFromScope,
  _notOwnedPaths,
  _contractsReferenced,
  _tasksFromTasksMd,
};

'use strict';

/**
 * verify kind collector — scans every contract under `.gsd-t/contracts/`
 * for status, gathers the success-criteria list from the active charter,
 * and surfaces the verify-gate plan reference (consumed by D5).
 *
 * Fail-open: missing optional source → null/empty field, brief still written.
 */

const fs = require('fs');
const path = require('path');

const NAME = 'verify';

function _readMaybe(file) {
  try { return fs.readFileSync(file, 'utf8'); } catch (_) { return null; }
}

function _scanContracts(projectDir, recordSource) {
  const dir = path.join(projectDir, '.gsd-t', 'contracts');
  let entries;
  try { entries = fs.readdirSync(dir); } catch (_) { return []; }
  const out = [];
  for (const f of entries) {
    if (!f.endsWith('.md')) continue;
    const rel = '.gsd-t/contracts/' + f;
    const text = _readMaybe(path.join(projectDir, f.startsWith('.') ? '' : '.gsd-t/contracts', f));
    if (!text) continue;
    recordSource(rel);
    let status = 'UNKNOWN';
    const m = text.match(/Status:\s*\**\s*(STABLE|DRAFT|PROPOSED)/i);
    if (m) status = m[1].toUpperCase();
    out.push({ path: rel, status });
  }
  out.sort((a, b) => (a.path < b.path ? -1 : a.path > b.path ? 1 : 0));
  return out;
}

/**
 * Extract numbered success-criterion entries (`1. ...`) from any charter
 * file under `.gsd-t/charters/`. Picks the most recent by mtime.
 */
function _successCriteriaFromCharter(projectDir, recordSource) {
  const dir = path.join(projectDir, '.gsd-t', 'charters');
  let entries;
  try { entries = fs.readdirSync(dir); } catch (_) { return { source: null, items: [] }; }
  const candidates = entries
    .filter((f) => f.endsWith('-charter.md') || f.endsWith('.md'))
    .map((f) => {
      const full = path.join(dir, f);
      let mt = 0;
      try { mt = fs.statSync(full).mtimeMs; } catch (_) { /* ignore */ }
      return { f, mt };
    })
    .sort((a, b) => b.mt - a.mt);
  if (!candidates.length) return { source: null, items: [] };

  const top = candidates[0];
  const rel = '.gsd-t/charters/' + top.f;
  const text = _readMaybe(path.join(projectDir, rel));
  if (!text) return { source: null, items: [] };
  recordSource(rel);

  // Find the success-criteria section: `## Falsifiable Success Criteria` (or similar).
  const re = /^##[^\n]*(?:Success Criteria|Falsifiable[^\n]*)\s*$([\s\S]*?)(?=^##\s+|\Z)/mi;
  const m = text.match(re);
  if (!m) return { source: rel, items: [] };

  const items = [];
  // Match `1. ...` or `1) ...` (number, dot or paren, space).
  const numberedRe = /^\s*\d+[.)]\s+(.+)$/gm;
  let nm;
  while ((nm = numberedRe.exec(m[1])) != null) {
    let item = nm[1].replace(/`/g, '').replace(/\*\*/g, '').trim();
    if (item.length > 200) item = item.slice(0, 197) + '...';
    items.push(item);
  }
  return { source: rel, items };
}

function _verifyGateContractRef(projectDir, recordSource) {
  const rel = '.gsd-t/contracts/verify-gate-contract.md';
  const full = path.join(projectDir, rel);
  if (!fs.existsSync(full)) return null;
  recordSource(rel);
  const text = _readMaybe(full);
  if (!text) return rel;
  return rel;
}

function _priorVerifyResults(projectDir, recordSource) {
  // Heuristic: most recent file under .gsd-t/verify/ if it exists.
  const dir = path.join(projectDir, '.gsd-t', 'verify');
  let entries;
  try { entries = fs.readdirSync(dir); } catch (_) { return null; }
  if (!entries.length) return null;
  const sorted = entries
    .map((f) => {
      const full = path.join(dir, f);
      let mt = 0;
      try { mt = fs.statSync(full).mtimeMs; } catch (_) {}
      return { f, mt };
    })
    .sort((a, b) => b.mt - a.mt);
  if (!sorted.length) return null;
  const rel = '.gsd-t/verify/' + sorted[0].f;
  recordSource(rel);
  return rel;
}

function collect(ctx) {
  const { projectDir, recordSource } = ctx;
  const contracts = _scanContracts(projectDir, recordSource);
  const sc = _successCriteriaFromCharter(projectDir, recordSource);
  const verifyGatePlan = _verifyGateContractRef(projectDir, recordSource);
  const priorVerifyResults = _priorVerifyResults(projectDir, recordSource);

  const ancillary = {
    charterSource: sc.source,
    contractStatusMap: contracts.reduce((m, c) => { m[c.path] = c.status; return m; }, {}),
    priorVerifyResults,
    successCriteria: sc.items,
    verifyGatePlan,
  };

  return {
    scope: { owned: [], notOwned: [], deliverables: [] },
    constraints: [],
    contracts,
    ancillary,
  };
}

module.exports = {
  name: NAME,
  requiresSources: [],
  collect,
  _scanContracts,
  _successCriteriaFromCharter,
};

'use strict';

/**
 * qa kind collector — points the QA subagent at its protocol path,
 * detects the project test runner, and surfaces the most recent
 * qa-issues entries.
 *
 * Fail-CLOSED: requires `templates/prompts/qa-subagent.md`. Library
 * enforces this via the `requiresSources` declaration.
 */

const fs = require('fs');
const path = require('path');

const NAME = 'qa';
const PROTOCOL = 'templates/prompts/qa-subagent.md';
const QA_ISSUES = '.gsd-t/qa-issues.md';
const TAIL_LIMIT = 10;

function _readMaybe(file) {
  try { return fs.readFileSync(file, 'utf8'); } catch (_) { return null; }
}

function _detectTestRunner(projectDir) {
  const detected = {
    npmTest: null,
    playwrightConfig: null,
    cypressConfig: null,
    jestConfig: null,
    vitestConfig: null,
  };

  const pkgPath = path.join(projectDir, 'package.json');
  try {
    const pkg = JSON.parse(fs.readFileSync(pkgPath, 'utf8'));
    if (pkg && pkg.scripts && typeof pkg.scripts.test === 'string') {
      detected.npmTest = pkg.scripts.test;
    }
  } catch (_) { /* fail-open */ }

  for (const f of ['playwright.config.ts', 'playwright.config.js', 'playwright.config.cjs', 'playwright.config.mjs']) {
    if (fs.existsSync(path.join(projectDir, f))) { detected.playwrightConfig = f; break; }
  }
  for (const f of ['cypress.config.ts', 'cypress.config.js', 'cypress.config.cjs']) {
    if (fs.existsSync(path.join(projectDir, f))) { detected.cypressConfig = f; break; }
  }
  for (const f of ['jest.config.ts', 'jest.config.js', 'jest.config.cjs']) {
    if (fs.existsSync(path.join(projectDir, f))) { detected.jestConfig = f; break; }
  }
  for (const f of ['vitest.config.ts', 'vitest.config.js', 'vitest.config.cjs', 'vitest.config.mjs']) {
    if (fs.existsSync(path.join(projectDir, f))) { detected.vitestConfig = f; break; }
  }

  return detected;
}

function _tailQaIssues(text) {
  if (!text) return [];
  const lines = text.split(/\r?\n/);
  // qa-issues.md is generally a markdown table; keep last N table rows
  // (rows beginning with `|` and not separator-only).
  const rows = lines.filter((l) => /^\|/.test(l) && !/^\|\s*-+\s*\|/.test(l));
  // Drop header (first row), then keep tail.
  const body = rows.slice(1);
  const tail = body.slice(-TAIL_LIMIT).map((l) => {
    const t = l.trim();
    return t.length > 200 ? t.slice(0, 197) + '...' : t;
  });
  return tail;
}

function _scanContracts(projectDir, recordSource) {
  const dir = path.join(projectDir, '.gsd-t', 'contracts');
  let entries;
  try { entries = fs.readdirSync(dir); } catch (_) { return []; }
  const out = [];
  for (const f of entries) {
    if (!f.endsWith('.md')) continue;
    const rel = '.gsd-t/contracts/' + f;
    const text = _readMaybe(path.join(projectDir, rel));
    if (!text) continue;
    recordSource(rel);
    const m = text.match(/Status:\s*\**\s*(STABLE|DRAFT|PROPOSED)/i);
    out.push({ path: rel, status: m ? m[1].toUpperCase() : 'UNKNOWN' });
  }
  out.sort((a, b) => (a.path < b.path ? -1 : a.path > b.path ? 1 : 0));
  return out;
}

function collect(ctx) {
  const { projectDir, recordSource } = ctx;

  recordSource(PROTOCOL);
  recordSource('package.json');

  const issuesText = _readMaybe(path.join(projectDir, QA_ISSUES));
  if (issuesText != null) recordSource(QA_ISSUES);

  const runner = _detectTestRunner(projectDir);
  const recentIssues = _tailQaIssues(issuesText);
  const contracts = _scanContracts(projectDir, recordSource);

  return {
    scope: { owned: [], notOwned: [], deliverables: [] },
    constraints: [],
    contracts,
    ancillary: {
      protocolPath: PROTOCOL,
      qaIssuesTail: recentIssues,
      testRunner: runner,
    },
  };
}

module.exports = {
  name: NAME,
  requiresSources: [PROTOCOL],
  collect,
  _detectTestRunner,
  _tailQaIssues,
};

'use strict';

/**
 * red-team kind collector — points the Red Team subagent at its protocol,
 * surfaces the recent commits in scope, and seeds attack vector hints
 * extracted from the protocol's "broken patches" section.
 *
 * Fail-CLOSED: requires `templates/prompts/red-team-subagent.md`. Library
 * enforces this via the `requiresSources` declaration.
 */

const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');

const NAME = 'red-team';
const PROTOCOL = 'templates/prompts/red-team-subagent.md';
const COMMIT_LIMIT = 10;

function _readMaybe(file) {
  try { return fs.readFileSync(file, 'utf8'); } catch (_) { return null; }
}

function _recentCommits(projectDir) {
  try {
    const stdout = execSync('git log -' + COMMIT_LIMIT + ' --oneline --no-color', {
      cwd: projectDir,
      encoding: 'utf8',
      stdio: ['ignore', 'pipe', 'ignore'],
    });
    return String(stdout || '')
      .split(/\r?\n/)
      .map((l) => l.trim())
      .filter(Boolean)
      .slice(0, COMMIT_LIMIT);
  } catch (_) {
    return [];
  }
}

/**
 * Pull attack-vector seeds out of the protocol's "Test Pass-Through" /
 * "broken patches" section, if present. Falls back to an empty array.
 *
 * The protocol enumerates examples in a `- Remove the listener entirely`
 * style — we extract those bullets verbatim (clipped) so the worker can
 * read them inline without re-fetching the protocol.
 */
function _attackVectorSeeds(protocolText) {
  if (!protocolText) return [];
  const out = [];
  // Match the section that explicitly lists broken-patch examples.
  // (heading variants: "broken patch", "Test Pass-Through", "Attack Categories")
  const headings = [
    /^[#]+[^\n]*broken patches?[^\n]*$/im,
    /^[#]+[^\n]*Test Pass-Through[^\n]*$/im,
    /^[#]+\s+Attack Categories[^\n]*$/im,
  ];
  for (const h of headings) {
    const hm = protocolText.match(h);
    if (!hm) continue;
    const start = hm.index + hm[0].length;
    const remainder = protocolText.slice(start);
    const next = remainder.match(/^[#]+\s+/m);
    const body = next ? remainder.slice(0, next.index) : remainder;
    for (const line of body.split(/\r?\n/)) {
      const bm = line.match(/^\s+[-*]\s+(.+)$/);
      if (!bm) continue;
      let item = bm[1].replace(/`/g, '').replace(/\*\*/g, '').trim();
      if (item.length > 160) item = item.slice(0, 157) + '...';
      out.push(item);
      if (out.length >= 8) break;
    }
    if (out.length) break;
  }
  return out;
}

function _scanContracts(projectDir, recordSource) {
  const dir = path.join(projectDir, '.gsd-t', 'contracts');
  let entries;
  try { entries = fs.readdirSync(dir); } catch (_) { return []; }
  const out = [];
  for (const f of entries) {
    if (!f.endsWith('.md')) continue;
    const rel = '.gsd-t/contracts/' + f;
    const text = _readMaybe(path.join(projectDir, rel));
    if (!text) continue;
    recordSource(rel);
    const m = text.match(/Status:\s*\**\s*(STABLE|DRAFT|PROPOSED)/i);
    out.push({ path: rel, status: m ? m[1].toUpperCase() : 'UNKNOWN' });
  }
  out.sort((a, b) => (a.path < b.path ? -1 : a.path > b.path ? 1 : 0));
  return out;
}

function collect(ctx) {
  const { projectDir, recordSource } = ctx;

  recordSource(PROTOCOL);

  const protocolText = _readMaybe(path.join(projectDir, PROTOCOL));
  const seeds = _attackVectorSeeds(protocolText);
  const recentCommits = _recentCommits(projectDir);
  const contracts = _scanContracts(projectDir, recordSource);

  return {
    scope: { owned: [], notOwned: [], deliverables: [] },
    constraints: [],
    contracts,
    ancillary: {
      attackVectorSeeds: seeds,
      protocolPath: PROTOCOL,
      recentCommits,
    },
  };
}

module.exports = {
  name: NAME,
  requiresSources: [PROTOCOL],
  collect,
  _recentCommits,
  _attackVectorSeeds,
};

'use strict';

/**
 * design-verify kind collector — points the Design Verification subagent
 * at its design contract path(s), extracts Figma URL(s), and surfaces
 * any screenshot manifest.
 *
 * Fail-CLOSED: requires at least one of:
 *   - `.gsd-t/contracts/design-contract.md` (flat)
 *   - `.gsd-t/contracts/design/INDEX.md` (hierarchical)
 *
 * The library enforces fail-closed via the FAIL_CLOSED_KINDS rule:
 * if NEITHER required source is present, generateBrief raises
 * EREQUIRED_MISSING. To express the OR-of-required-sources, the
 * collector itself emits the structured error during `collect`.
 */

const fs = require('fs');
const path = require('path');

const NAME = 'design-verify';
const FLAT_CONTRACT = '.gsd-t/contracts/design-contract.md';
const HIER_INDEX = '.gsd-t/contracts/design/INDEX.md';
const SCREENSHOT_MANIFEST = '.gsd-t/screenshots/manifest.json';

function _readMaybe(file) {
  try { return fs.readFileSync(file, 'utf8'); } catch (_) { return null; }
}

function _figmaUrls(text) {
  if (!text) return [];
  const re = /https?:\/\/(?:www\.)?figma\.com\/[A-Za-z0-9_./?#=&%-]+/g;
  const out = [];
  const seen = new Set();
  let m;
  while ((m = re.exec(text)) != null) {
    const u = m[0].replace(/[).,;]+$/, '');
    if (seen.has(u)) continue;
    seen.add(u);
    out.push(u);
  }
  return out;
}

function _designContractsList(projectDir, recordSource) {
  const out = [];
  // Flat: design-contract*.md at top of contracts/
  const contractsDir = path.join(projectDir, '.gsd-t', 'contracts');
  let entries;
  try { entries = fs.readdirSync(contractsDir); } catch (_) { entries = []; }
  for (const f of entries) {
    if (/^design.*\.md$/i.test(f)) {
      const rel = '.gsd-t/contracts/' + f;
      out.push(rel);
      recordSource(rel);
    }
  }
  // Hierarchical: .gsd-t/contracts/design/**/*.md
  const designDir = path.join(contractsDir, 'design');
  if (fs.existsSync(designDir)) {
    const stack = [designDir];
    while (stack.length) {
      const cur = stack.pop();
      let inner;
      try { inner = fs.readdirSync(cur, { withFileTypes: true }); } catch (_) { continue; }
      for (const ent of inner) {
        const full = path.join(cur, ent.name);
        if (ent.isDirectory()) {
          stack.push(full);
        } else if (ent.isFile() && full.endsWith('.md')) {
          const rel = path.relative(projectDir, full);
          out.push(rel);
          recordSource(rel);
        }
      }
    }
  }
  out.sort();
  return out;
}

function collect(ctx) {
  const { projectDir, recordSource } = ctx;

  // Required-source OR check (library only knows AND-of-required, so we
  // express the OR rule here).
  const flatPresent = fs.existsSync(path.join(projectDir, FLAT_CONTRACT));
  const hierPresent = fs.existsSync(path.join(projectDir, HIER_INDEX));
  if (!flatPresent && !hierPresent) {
    const err = new Error('design-verify: no design contract found (' +
      FLAT_CONTRACT + ' or ' + HIER_INDEX + ')');
    err.code = 'EREQUIRED_MISSING';
    err.missing = [FLAT_CONTRACT, HIER_INDEX];
    throw err;
  }

  const designPaths = _designContractsList(projectDir, recordSource);

  // Pull all Figma URLs across every located design contract.
  const figmaUrls = [];
  const seen = new Set();
  for (const rel of designPaths) {
    const text = _readMaybe(path.join(projectDir, rel));
    if (!text) continue;
    for (const u of _figmaUrls(text)) {
      if (seen.has(u)) continue;
      seen.add(u);
      figmaUrls.push(u);
    }
  }
  figmaUrls.sort();

  let screenshotManifest = null;
  if (fs.existsSync(path.join(projectDir, SCREENSHOT_MANIFEST))) {
    screenshotManifest = SCREENSHOT_MANIFEST;
    recordSource(SCREENSHOT_MANIFEST);
  }

  return {
    scope: { owned: [], notOwned: [], deliverables: [] },
    constraints: [],
    contracts: designPaths.map((p) => ({ path: p, status: 'UNKNOWN' })),
    ancillary: {
      designContractPaths: designPaths,
      figmaUrls,
      screenshotManifest,
    },
  };
}

module.exports = {
  name: NAME,
  // Library treats requiresSources as AND. design-verify uses the OR-of-two
  // pattern instead, raising EREQUIRED_MISSING from inside collect().
  requiresSources: [],
  collect,
  _figmaUrls,
  _designContractsList,
};

