216	function _readSpawnPlans(projectDir, notes) {
217	  const dir = path.join(projectDir, '.gsd-t', 'spawns');
218	  let files;
219	  try {
220	    if (!fs.existsSync(dir)) return [];
221	    files = fs.readdirSync(dir).filter((n) => n.endsWith('.json'));
222	  } catch (err) {
223	    notes.push('spawns dir unreadable: ' + (err && err.message || err));
224	    return [];
225	  }
226	  const plans = [];
227	  for (const f of files) {
228	    const full = path.join(dir, f);
229	    let raw;
230	    try {
231	      raw = fs.readFileSync(full, 'utf8');
232	    } catch (err) {
233	      notes.push('spawn-plan read failed: ' + full);
234	      continue;
235	    }
236	    let parsed;
237	    try {
238	      parsed = JSON.parse(raw);
239	    } catch (err) {
