400	    if (durations.length === 0) return { value: 0, mode: 'post-wave' };
401	    const starts = inWave.map((p) => _safeDate(p.startedAt)).filter(Boolean).map((d) => d.getTime());
402	    const ends = inWave.map((p) => _safeDate(p.endedAt) || now).map((d) => d.getTime());
403	    if (starts.length === 0 || ends.length === 0) return { value: 0, mode: 'post-wave' };
404	    const span_s = (Math.max(...ends) - Math.min(...starts)) / 1000;
405	    const sumDur = durations.reduce((a, b) => a + b, 0);
406	    if (span_s <= 0) return { value: 0, mode: 'post-wave' };
407	    return { value: sumDur / span_s, mode: 'post-wave' };
408	  }
409	
410	  return { value: 0, mode: 'idle' };
411	}
